import { Platform } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const IS_DEV = __DEV__;
const SENSITIVE_KEYS = ['token', 'password', 'auth', 'secret', 'key', 'credential', 'ssn', 'card'];

const maskSensitiveData = (data) => {
  if (!data) return data;
  
  if (typeof data === 'string') {
    return data.length > 4 ? `${data.substring(0, 2)}***${data.substring(data.length - 2)}` : '****';
  }
  
  if (Array.isArray(data)) {
    return data.map(item => maskSensitiveData(item));
  }
  
  if (typeof data === 'object') {
    const masked = {};
    for (const key in data) {
      const isSensitive = SENSITIVE_KEYS.some(sk => key.toLowerCase().includes(sk));
      masked[key] = isSensitive ? '***REDACTED***' : maskSensitiveData(data[key]);
    }
    return masked;
  }
  
  return data;
};

const sanitizeUrl = (url) => {
  try {
    const urlObj = new URL(url);
    SENSITIVE_KEYS.forEach(key => {
      if (urlObj.searchParams.has(key)) {
        urlObj.searchParams.set(key, '***REDACTED***');
      }
    });
    return urlObj.toString();
  } catch {
    return url;
  }
};

class SecureLogger {
  constructor() {
    this.enabled = IS_DEV;
    this.sessionId = Date.now().toString(36);
  }

  logNetwork(method, url, requestData, responseData, statusCode) {
    if (!this.enabled) return;
    
    console.log('[NETWORK]', {
      method,
      url: sanitizeUrl(url),
      status: statusCode,
      timestamp: new Date().toISOString(),
      request: maskSensitiveData(requestData),
      response: maskSensitiveData(responseData)
    });
  }

  logStorage(operation, key, value) {
    if (!this.enabled) return;
    
    const isSensitive = SENSITIVE_KEYS.some(sk => key.toLowerCase().includes(sk));
    console.log('[STORAGE]', {
      operation,
      key,
      value: isSensitive ? '***REDACTED***' : maskSensitiveData(value),
      timestamp: new Date().toISOString()
    });
  }

  logAction(action, data) {
    if (!this.enabled) return;
    
    console.log('[ACTION]', {
      action,
      data: maskSensitiveData(data),
      timestamp: new Date().toISOString()
    });
  }

  logStateChange(stateName, newState) {
    if (!this.enabled) return;
    
    console.log('[STATE]', {
      state: stateName,
      value: maskSensitiveData(newState),
      timestamp: new Date().toISOString()
    });
  }

  logError(error, context) {
    console.error('[ERROR]', {
      message: error.message,
      context: maskSensitiveData(context),
      timestamp: new Date().toISOString(),
      stack: IS_DEV ? error.stack : undefined
    });
  }
}

export const logger = new SecureLogger();

export const secureAsyncStorage = {
  async getItem(key) {
    const value = await AsyncStorage.getItem(key);
    logger.logStorage('GET', key, value);
    return value;
  },
  
  async setItem(key, value) {
    await AsyncStorage.setItem(key, value);
    logger.logStorage('SET', key, value);
  },
  
  async removeItem(key) {
    await AsyncStorage.removeItem(key);
    logger.logStorage('REMOVE', key, null);
  }
};

export const createSecureFetch = (originalFetch = fetch) => {
  return async (url, options = {}) => {
    const startTime = Date.now();
    
    try {
      const response = await originalFetch(url, options);
      const clonedResponse = response.clone();
      
      let responseData;
      try {
        responseData = await clonedResponse.json();
      } catch {
        responseData = await clonedResponse.text();
      }
      
      logger.logNetwork(
        options.method || 'GET',
        url,
        options.body,
        responseData,
        response.status
      );
      
      return response;
    } catch (error) {
      logger.logError(error, { url, method: options.method });
      throw error;
    }
  };
};